class Solution {
    public int flipLights(int n, int presses) {
        n = (n + 2) / 3;
        if (presses == 0) return 1;
        if (presses == 1) return Math.min(2, n);
        if (presses == 2) return Math.min(4, (int) Math.pow(2, Math.min(n, 2)));
        return Math.min(7, (int) Math.pow(2, Math.min(n, 3)));
    }
}
```
